/*! * \file HAN_IoT_Shield.h * \brief functions to use hardware peripherals on the HAN IoT Shield. * \author Remko Welling (remko.welling@han.nl) * \date 17-12-2018 * \version 1.1 * * Version|Date |Note * -------|------------|---- * 1.2 | 4- 2-2019 | Modified include "arduino.h" to "Arduino.h" to be linux compliant * 1.1 | 27-12-2018 | Updates on documentation * 1.0 | 15-12-2018 | Initial version * * */
/*! \todo make documentation complete
# HAN_IoT Shield Documentation
## Shield layout
\verbatim
+-----------------------------+ | [gr-1] [gr-2] [gr-2] [gr-2] | <- 4 grove connectors | | | +--------+ +--------+ | | | | | | | | | P1 | | P2 | | <- 2 potentiometers | | | | | | | +--------+ +--------+ | | | | +----+ +----+ | | |Red | |Blck| | <- 2 push button switches | +----+ +----+ | | | | [led1] [led3] [led2] [led4] | <- 4 LEDs | | | [Dallas] | <- Dallas one wire temperature sensor +-\ /---------+ \---------------/
\endverbatim
*/
#ifndef _HAN_IOT_SHIELD_H_ #define _HAN_IOT_SHIELD_H_
#include <Arduino.h>
// Defines for LEDs #define PIN_LED_1_RED 3 ///< Led 1 is red and connected to arduino pin 3 #define PIN_LED_2_RED 4 ///< Led 2 is red and connected to arduino pin 4 #define PIN_LED_3_GRN 5 ///< Led 3 is green and connected to arduino pin 5 #define PIN_LED_4_GRN 6 ///< Led 4 is green and connected to arduino pin 6
// Defines for pushbutton #define PIN_SWITCH_BLACK 8 ///< Black switch is connected to pin Arduino pin 8 #define PIN_SWITCH_RED 9 ///< Red switch is connected to pin Arduino pin 9 #define RELEASED HIGH ///< represent activity of pushbutton, Released or not pressed is HIGH or '1' #define PRESSED LOW ///< represent activity of pushbutton, Pressed is LOW or '0'
#endif // _HAN_IOT_SHIELD_H_

