  (http://creativecommons.org/licenses/by-nc/4.0/) by
  Remko Welling (https://ese.han.nl/~rwelling/) E-mail: remko.welling@han.nl

  The program is distributed in the hope that it will be useful,
  but WITHOUT ANY WARRANTY; without even the implied warranty of
  MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.
  --------------------------------------------------------------------*/

/*!
 * \file SensingModule.h
 * \brief Module for sensing components on the HAN IoT Shield.
 * \author Remko Welling (remko.welling@han.nl)
 */

#ifndef _SENSING_MODULE_H_
#define _SENSING_MODULE_H_

#include <Arduino.h>
#include <OneWire.h>
#include <DallasTemperature.h>

// defines for potentiometers.
#define PIN_POT_RED      A0    ///< Potmeter 1 with red knob is connected to Arduino pin A0
#define PIN_POT_WHITE    A1    ///< Potmeter 1 with white knob is connected to Arduino pin A1

// defines for Dallas one wire sensor
#define PIN_DALLAS       2     ///< Dallas DS18S20 one-wire temperature sensor is connected to Arduino pin 2

class iotShieldPotmeter
{
private:
  uint8_t _pin;                 ///< Hardware pin to which the potentiometer is connected.
  int16_t _aRange;              ///< Minimum value that the potentiometer will give
  int16_t _bRange;              ///< Maximum value that the potentiometer will give.

public:
  /// \brief constructor
  /// \pre requires a analog input pin to which the potentiometer is connected
  /// The potentiometer shall apply 0 to VCC to the analog input.
  /// \param hardwarePin Arduino pin to which the potentiometer is connected
  /// \param minimumValue of the range within the potentiometer will generate values. Default is 0
  /// \param maximumValue of the range within the potentiometer will generate values. Default is 1023.
  iotShieldPotmeter(uint8_t hardwarePin, int minimumValue = 0, int maximumValue = 1023);

  /// \brief Default destructor
  ~iotShieldPotmeter();

  /// \brief read value from potentiometer
  /// This function will transpose raw analog value from 0 to 1023 into the range
  /// specified by the minimum and maximum value given at creation of the object.
  /// \return float transposed value from potentiometer into the specified range.
  float getValue(void);
};

class iotShieldTempSensor
{
private:
  float   _temperature;         ///< Local value to hold temperature read from Dallas sensor
  OneWire _oneWireInterface;    ///< Object of onewire interface
  DallasTemperature _sensors;   ///< Object of one wire sensors on one wire bus

public:
  /// \pre requires a digital input pin to which the sensor is connected
  /// \param hardwarePin Arduino pin to which the sensor is connected
  iotShieldTempSensor(uint8_t hardwarePin = PIN_DALLAS);

  /// \brief Default destructor
  ~iotShieldTempSensor();

  /// \brief get temperature in Celsius
  /// \return float temperature in Celsius
  float getTemperatureCelsius();
};

class iotShieldCO2Sensor
{
private:
  unsigned long _startTime;

public:
  /// \brief constructor
  iotShieldCO2Sensor();

  /// \brief Default destructor
  ~iotShieldCO2Sensor();

  /// \brief get simulated CO2 value in ppm
  /// \return float CO2 concentration in ppm
  float getCO2ppm();
};

#endif // _SENSING_MODULE_H_

#include <TheThingsNetwork.h>
#include <CayenneLPP.h>
#include "HAN_IoT_Shield.h"
#include "SensingModule.h"

// TTN Credentials
const char *appEui = "1234123412341234";
const char *appKey = "CC33FF50DEAF68B3C9B80F465233A745";

#define loraSerial Serial1
#define debugSerial Serial
#define freqPlan TTN_FP_EU868

TheThingsNetwork ttn(loraSerial, debugSerial, freqPlan);
CayenneLPP lpp(51);

// IoT Shield
iotShieldPotmeter potmeter1(PIN_POT_RED, -175, 300);
iotShieldPotmeter potmeter2(PIN_POT_WHITE, -50, 100);
iotShieldCO2Sensor co2Sensor;
iotShieldButton redButton(PIN_SWITCH_RED);
iotShieldButton blackButton(PIN_SWITCH_BLACK);
iotShieldLED leftRedLED(PIN_LED_1_RED);
iotShieldLED rightRedLED(PIN_LED_2_RED);
iotShieldLED leftGreenLED(PIN_LED_3_GRN);
iotShieldLED rightGreenLED(PIN_LED_4_GRN);

// Global variables
#define SAFE_INTERVAL 60000UL
#define WATCH_INTERVAL 30000UL
#define WARNING_INTERVAL 15000UL
#define ALARM_INTERVAL 5000UL

#define ESCALATE_COUNT 3 // consecutive high readings to escalate state
#define DEESCALATE_COUNT 5 // consecutive low readings to deescalate state

#define TEMPERATURE_SHIFT 30
#define TEMPERATURE_DIV_RANGE 70
#define HUMIDITY_SHIFT 50
#define HUMIDITY_DIV_RANGE 50
unsigned long lastTx = 0;

enum alarmState { safe, watch, warning, alarm};
alarmState currentState = safe;

uint8_t escalateCount = 0;
uint8_t deescalateCount = 0;
bool alarmActive = false;

unsigned long lastBlink = 0;
bool blinkState = false;
#define BLINK_INTERVAL 500UL

unsigned long lastTick = 0;
#define TICK_INTERVAL 100UL

float computeScore(float temp, float humidity) {
  // shifts the temperature, anything below will be counted as 'normal'. (anything below 30 degrees)
  // divide by the range from the shift to the highest (100 - 30 = 70)
  float tScore = constrain((temp - TEMPERATURE_SHIFT) / TEMPERATURE_DIV_RANGE, 0, 1.0) * 100; 

  // lower humidity percentage indicates a fire, so it is inversed from temperature
  // anyhting below 50 concerning
  float hScore = constrain((HUMIDITY_SHIFT - humidity) / HUMIDITY_DIV_RANGE, 0, 1.0) * 100;

  return (tScore * 0.6) + (hScore * 0.4);
}

unsigned long getIntervalTx(alarmState state) {
  switch(state) {
    case watch: return WATCH_INTERVAL;
    case warning: return WARNING_INTERVAL;
    case alarm: return ALARM_INTERVAL;
    default: return SAFE_INTERVAL;
  }
}

void updateState(float score) {
  alarmState newState;

  if (score >= 70) {
    newState = alarm;
  } else if (score >= 45) {
    newState = warning;
  } else if (score >= 25) {
    newState = watch;
  } else {
    newState = safe;
  }

  if (newState > currentState) {
    escalateCount++;
    deescalateCount = 0;
    if (escalateCount >= ESCALATE_COUNT) {
      currentState = newState;
      escalateCount = 0;
      debugSerial.println("--State UP: " + String(currentState));
    }
  } else if (newState < currentState) {
      deescalateCount++;
      escalateCount = 0;
      if (deescalateCount >= DEESCALATE_COUNT) {
        if (!alarmActive) { // only clear if it wasn't a manual alarm press
          currentState = newState;
          deescalateCount = 0;
          debugSerial.println("--State DOWN: " + String(currentState));
        }
      }
    } else {
      escalateCount = 0;
      deescalateCount = 0;
    }
}

void updateLEDs() {
  leftGreenLED.setState(LED_OFF);
  leftRedLED.setState(LED_OFF);
  rightRedLED.setState(LED_OFF);

  switch (currentState) {
    case safe:
      break;
    case watch:
      leftGreenLED.setState(LED_ON);
      break;
    case warning:
      leftGreenLED.setState(LED_ON);
      rightRedLED.setState(LED_ON);
      break;
    case alarm:
      if (millis() - lastBlink >= BLINK_INTERVAL) {
        blinkState = !blinkState;
        leftRedLED.setState(blinkState ? LED_ON : LED_OFF);
        lastBlink = millis();
      }

      break;
  }
}

void sendPayload(float temperature, float humidity, float score) {
  rightGreenLED.setState(LED_ON);

  lpp.reset();
  lpp.addTemperature(1, temperature);
  lpp.addRelativeHumidity(2, humidity);
  lpp.addAnalogInput(3, score);
  lpp.addPresence(4, alarmActive ? 1 : 0);
  lpp.addDigitalInput(5, (uint8_t)currentState);

  ttn.sendBytes(lpp.getBuffer(), lpp.getSize());

  rightGreenLED.setState(LED_OFF);
  debugSerial.println("-- payload sent | State: " + String(currentState) + " | Score: " + String(score));
}

void setup()
{
  loraSerial.begin(57600);
  debugSerial.begin(9600);
  while (!debugSerial && millis() < 10000)
    ;
  debugSerial.println("-- STATUS");
  ttn.showStatus();
  debugSerial.println("-- JOIN");
  ttn.join(appEui, appKey);
}

void loop()
{
  // Red button = immediate alarm
  if (redButton.isPressed()) {
    alarmActive = true;
    currentState = alarm; 
    byte alarm[2];
    alarm[0] = 0xFF;
    alarm[1] = 0x01;
    ttn.sendBytes(alarm, sizeof(alarm));
    debugSerial.println("-- MANUAL ALARM SENT");
    lastTx = millis(); // reset timer so next periodic isn't immediate
  }

  // Black button = poll for downlink
  if (blackButton.isPressed()) {
  if (alarmActive) {
    // Reset alarm
    alarmActive  = false;
    currentState = safe;
    leftRedLED.setState(LED_OFF);
    debugSerial.println("-- ALARM RESET");
  } else {
    // No alarm active = poll for downlink
    ttn.sendBytes(NULL, 0);
    debugSerial.println("-- POLL SENT");
  }
}


  if (millis() - lastTick >= TICK_INTERVAL) {
    // Read sensors
    float temperature = potmeter1.getValue();
    float humidity    = potmeter2.getValue();
    float score       = computeScore(temperature, humidity);

    debugSerial.println("Temp: "     + String(temperature));
    debugSerial.println("Humidity: " + String(humidity));
    debugSerial.println("Score: " + String(score));

    updateState(score);

    updateLEDs();

    // Periodic send
    if (millis() - lastTx >= getIntervalTx(currentState)) {
      sendPayload(temperature, humidity, score);
      lastTx = millis();
    }

    lastTick = millis();
  }

}

#include <TheThingsNetwork.h>
#include <CayenneLPP.h>
#include "HAN_IoT_Shield.h"
#include "SensingModule.h"

// TTN Credentials
const char *appEui = "1234123412341234";
const char *appKey = "CC33FF50DEAF68B3C9B80F465233A745";

#define loraSerial Serial1
#define debugSerial Serial
#define freqPlan TTN_FP_EU868

TheThingsNetwork ttn(loraSerial, debugSerial, freqPlan);
CayenneLPP lpp(51);

// IoT Shield
iotShieldPotmeter potmeter1(PIN_POT_RED, -175, 300);
iotShieldPotmeter potmeter2(PIN_POT_WHITE, -50, 100);
iotShieldCO2Sensor co2Sensor;
iotShieldButton redButton(PIN_SWITCH_RED);
iotShieldButton blackButton(PIN_SWITCH_BLACK);
iotShieldLED leftRedLED(PIN_LED_1_RED);
iotShieldLED rightRedLED(PIN_LED_2_RED);
iotShieldLED leftGreenLED(PIN_LED_3_GRN);
iotShieldLED rightGreenLED(PIN_LED_4_GRN);

// Global variables
#define SAFE_INTERVAL 60000UL
#define WATCH_INTERVAL 30000UL
#define WARNING_INTERVAL 15000UL
#define ALARM_INTERVAL 5000UL

#define ESCALATE_COUNT 3 // consecutive high readings to escalate state
#define DEESCALATE_COUNT 5 // consecutive low readings to deescalate state

#define TEMPERATURE_SHIFT 30
#define TEMPERATURE_DIV_RANGE 70
#define HUMIDITY_SHIFT 50
#define HUMIDITY_DIV_RANGE 50
unsigned long lastTx = 0;

enum alarmState { safe, watch, warning, alarm};
alarmState currentState = safe;

uint8_t escalateCount = 0;
uint8_t deescalateCount = 0;
bool alarmActive = false;

unsigned long lastBlink = 0;
bool blinkState = false;
#define BLINK_INTERVAL 500UL

unsigned long lastTick = 0;
#define TICK_INTERVAL 100UL

float computeScore(float temp, float humidity, float co2) {
  // shifts the temperature, anything below will be counted as 'normal'. (anything below 30 degrees)
  // divide by the range from the shift to the highest (100 - 30 = 70)
  float tScore = constrain((temp - TEMPERATURE_SHIFT) / TEMPERATURE_DIV_RANGE, 0, 1.0) * 100; 

  // lower humidity percentage indicates a fire, so it is inversed from temperature
  // anyhting below 50 concerning
  float hScore = constrain((HUMIDITY_SHIFT - humidity) / HUMIDITY_DIV_RANGE, 0, 1.0) * 100;

  // high CO2 indicates fire, base 400 ppm, concerning above 600 ppm
  float cScore = constrain((co2 - 400.0) / 600.0, 0, 1.0) * 100;

  return (tScore * 0.4) + (hScore * 0.3) + (cScore * 0.3);
}

unsigned long getIntervalTx(alarmState state) {
  switch(state) {
    case watch: return WATCH_INTERVAL;
    case warning: return WARNING_INTERVAL;
    case alarm: return ALARM_INTERVAL;
    default: return SAFE_INTERVAL;
  }
}

void updateState(float score) {
  alarmState newState;

  if (score >= 70) {
    newState = alarm;
  } else if (score >= 45) {
    newState = warning;
  } else if (score >= 25) {
    newState = watch;
  } else {
    newState = safe;
  }

  if (newState > currentState) {
    escalateCount++;
    deescalateCount = 0;
    if (escalateCount >= ESCALATE_COUNT) {
      currentState = newState;
      escalateCount = 0;
      debugSerial.println("--State UP: " + String(currentState));
    }
  } else if (newState < currentState) {
      deescalateCount++;
      escalateCount = 0;
      if (deescalateCount >= DEESCALATE_COUNT) {
        if (!alarmActive) { // only clear if it wasn't a manual alarm press
          currentState = newState;
          deescalateCount = 0;
          debugSerial.println("--State DOWN: " + String(currentState));
        }
      }
    } else {
      escalateCount = 0;
      deescalateCount = 0;
    }
}

void updateLEDs() {
  leftGreenLED.setState(LED_OFF);
  leftRedLED.setState(LED_OFF);
  rightRedLED.setState(LED_OFF);

  switch (currentState) {
    case safe:
      break;
    case watch:
      leftGreenLED.setState(LED_ON);
      break;
    case warning:
      leftGreenLED.setState(LED_ON);
      rightRedLED.setState(LED_ON);
      break;
    case alarm:
      if (millis() - lastBlink >= BLINK_INTERVAL) {
        blinkState = !blinkState;
        leftRedLED.setState(blinkState ? LED_ON : LED_OFF);
        lastBlink = millis();
      }

      break;
  }
}

void sendPayload(float temperature, float humidity, float score) {
  rightGreenLED.setState(LED_ON);

  lpp.reset();
  lpp.addTemperature(1, temperature);
  lpp.addRelativeHumidity(2, humidity);
  lpp.addAnalogInput(3, score);
  lpp.addPresence(4, alarmActive ? 1 : 0);
  lpp.addDigitalInput(5, (uint8_t)currentState);

  ttn.sendBytes(lpp.getBuffer(), lpp.getSize());

  rightGreenLED.setState(LED_OFF);
  debugSerial.println("-- payload sent | State: " + String(currentState) + " | Score: " + String(score));
}

void setup()
{
  loraSerial.begin(57600);
  debugSerial.begin(9600);
  while (!debugSerial && millis() < 10000)
    ;
  debugSerial.println("-- STATUS");
  ttn.showStatus();
  debugSerial.println("-- JOIN");
  ttn.join(appEui, appKey);
}

void loop()
{
  // Red button = immediate alarm
  if (redButton.isPressed()) {
    alarmActive = true;
    currentState = alarm; 
    byte alarm[2];
    alarm[0] = 0xFF;
    alarm[1] = 0x01;
    ttn.sendBytes(alarm, sizeof(alarm));
    debugSerial.println("-- MANUAL ALARM SENT");
    lastTx = millis(); // reset timer so next periodic isn't immediate
  }

  // Black button = poll for downlink
  if (blackButton.isPressed()) {
  if (alarmActive) {
    // Reset alarm
    alarmActive  = false;
    currentState = safe;
    leftRedLED.setState(LED_OFF);
    debugSerial.println("-- ALARM RESET");
  } else {
    // No alarm active = poll for downlink
    ttn.sendBytes(NULL, 0);
    debugSerial.println("-- POLL SENT");
  }
}


  if (millis() - lastTick >= TICK_INTERVAL) {
    // Read sensors
    float temperature = potmeter1.getValue();
    float humidity    = potmeter2.getValue();
    float co2          = co2Sensor.getPPM();
    float score       = computeScore(temperature, humidity, co2);

    debugSerial.println("Temp: "     + String(temperature));
    debugSerial.println("Humidity: " + String(humidity));
    debugSerial.println("CO2: "      + String(co2));
    debugSerial.println("Score: " + String(score));

    updateState(score);

    updateLEDs();

    // Periodic send
    if (millis() - lastTx >= getIntervalTx(currentState)) {
      sendPayload(temperature, humidity, score);
      lastTx = millis();
    }

    lastTick = millis();
  }

}
